tool_calls:
awk -F',' '
function jesc(s,   t) {
  gsub(/\\/, "\\\\", s)
  gsub(/"/, "\\\"", s)
  gsub(/\t/, "\\t", s)
  gsub(/\r/, "\\r", s)
  gsub(/\n/, "\\n", s)
  return s
}
NR==1 {
  n=split($0, h, FS)
  next
}
{
  if (count==0) printf "["
  else printf ","
  printf "{"
  for (i=1; i<=n; i++) {
    if (i>1) printf ","
    printf "\"%s\":\"%s\"", jesc(h[i]), jesc($i)
  }
  printf "}"
  count++
}
END {
  if (count==0) printf "[]\n"
  else printf "]\n"
}
' /data/users.csv

